using JuMP

function foo()
    model = Model()

    N=3
    M=4

    @variable(model, x[1:N,1:M], Bin)
    LHS = sum(x, dims=4)
    RHS = fill(1, (N))
    @assert size(LHS) == (N, M)
    @assert size(RHS) == (N, )
    @assert size(LHS) != size(RHS)
    @constraints(model, begin
        LHS .<= RHS
    end);
    print(model)
end

foo()
```
LHS (erroneously) has dimensionality different from that of the RHS.
